package main

import (
	"context"
	"fmt"
	"io"
	"net"
	"net/http"
	"net/url"
	"os"
	"regexp"
	"strings"
	"time"

	"github.com/labstack/echo/v4"
)

// Request body
type PreviewRequest struct {
	URL string `json:"url"`
}

// Response body
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
}

const maxResponseBodySize = 5 * 1024 * 1024 // 5 MB

// AllowLocalhost can be set to true for testing purposes
var AllowLocalhost = os.Getenv("ALLOW_LOCALHOST") == "true"

// isPrivateIP checks if an IP address is in a private/reserved range
func isPrivateIP(ip net.IP) bool {
	privateRanges := []string{
		"10.0.0.0/8",     // Private A
		"172.16.0.0/12",  // Private B
		"192.168.0.0/16", // Private C
		"169.254.0.0/16", // Link-local
		"0.0.0.0/8",      // Current network
		"100.64.0.0/10",  // Shared address space
		"192.0.0.0/24",   // IETF Protocol
		"192.0.2.0/24",   // TEST-NET-1
		"198.51.100.0/24", // TEST-NET-2
		"203.0.113.0/24", // TEST-NET-3
		"224.0.0.0/4",    // Multicast
		"240.0.0.0/4",    // Reserved
		"255.255.255.255/32", // Broadcast
		"fc00::/7",       // IPv6 unique local
		"fe80::/10",      // IPv6 link-local
	}

	// Loopback ranges
	loopbackRanges := []string{
		"127.0.0.0/8",    // Loopback
		"::1/128",        // IPv6 loopback
	}

	for _, cidr := range privateRanges {
		_, network, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if network.Contains(ip) {
			return true
		}
	}

	if !AllowLocalhost {
		for _, cidr := range loopbackRanges {
			_, network, err := net.ParseCIDR(cidr)
			if err != nil {
				continue
			}
			if network.Contains(ip) {
				return true
			}
		}
	}

	// Check IPv4-mapped IPv6 addresses
	if ip4 := ip.To4(); ip4 != nil && !ip.Equal(net.ParseIP(ip4.String())) {
		return isPrivateIP(ip4)
	}

	return false
}

// isLoopbackHost checks if the host is a loopback address or "localhost"
func isLoopbackHost(host string) bool {
	h := host
	if hp, _, err := net.SplitHostPort(host); err == nil {
		h = hp
	}
	if strings.EqualFold(h, "localhost") {
		return true
	}
	if ip := net.ParseIP(h); ip != nil {
		return ip.IsLoopback()
	}
	return false
}

// validateHost resolves the hostname and checks that it doesn't point to a private IP
func validateHost(hostname string) error {
	// Strip port if present
	host := hostname
	if h, _, err := net.SplitHostPort(hostname); err == nil {
		host = h
	}

	if host == "" {
		return fmt.Errorf("empty host")
	}

	// Check if it's a raw IP
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
		return nil
	}

	// Check for localhost hostname
	if !AllowLocalhost && strings.EqualFold(host, "localhost") {
		return fmt.Errorf("access to private IP addresses is not allowed")
	}

	// Resolve hostname
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %w", err)
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	return nil
}

func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid JSON"})
	}

	// Validate URL
	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL format"})
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Only HTTP/HTTPS URLs are allowed"})
	}

	if parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL must contain a valid host"})
	}

	// Validate host against SSRF - check that the resolved IP is not private
	if err := validateHost(parsedURL.Host); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": err.Error()})
	}

	// Create a custom dialer that validates IPs at connection time to prevent DNS rebinding / TOCTOU
	safeDialer := &net.Dialer{
		Timeout: 3 * time.Second,
	}

	safeTransport := &http.Transport{
		DialContext: func(dialCtx context.Context, network, addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, fmt.Errorf("invalid address: %w", err)
			}

			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, fmt.Errorf("failed to resolve host: %w", err)
			}

			// Filter out private IPs
			var validIPs []net.IP
			for _, ip := range ips {
				if !isPrivateIP(ip) {
					validIPs = append(validIPs, ip)
				}
			}

			if len(validIPs) == 0 {
				return nil, fmt.Errorf("access to private IP addresses is not allowed")
			}

			// Connect to the first valid IP
			for _, ip := range validIPs {
				conn, err := safeDialer.DialContext(dialCtx, network, net.JoinHostPort(ip.String(), port))
				if err == nil {
					return conn, nil
				}
			}
			return nil, fmt.Errorf("failed to connect to any resolved address")
		},
	}

	client := &http.Client{
		Timeout:   5 * time.Second,
		Transport: safeTransport,
		CheckRedirect: func(req2 *http.Request, via []*http.Request) error {
			if len(via) >= 5 {
				return fmt.Errorf("too many redirects")
			}
			// Validate redirect target
			if req2.URL.Scheme != "http" && req2.URL.Scheme != "https" {
				return fmt.Errorf("redirect to non-HTTP scheme not allowed")
			}
			if err := validateHost(req2.URL.Host); err != nil {
				return fmt.Errorf("redirect to disallowed host: %w", err)
			}
			return nil
		},
	}

	httpReq, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Failed to create request"})
	}
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Limit the response body size to prevent memory exhaustion
	limitedReader := io.LimitReader(resp.Body, maxResponseBodySize)
	body, err := io.ReadAll(limitedReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	html := string(htmlContent)

	var title, description string

	// Extract title
	titleRe := regexp.MustCompile(`(?i)<title[^>]*>(.*?)</title>`)
	if matches := titleRe.FindStringSubmatch(html); len(matches) > 1 {
		title = strings.TrimSpace(matches[1])
	}

	// Extract meta description
	metaDescRe := regexp.MustCompile(`(?i)<meta\s+[^>]*name\s*=\s*["']description["'][^>]*content\s*=\s*["']([^"']*)["'][^>]*/?>`)
	if matches := metaDescRe.FindStringSubmatch(html); len(matches) > 1 {
		description = strings.TrimSpace(matches[1])
	} else {
		// Try alternate attribute order: content before name
		metaDescRe2 := regexp.MustCompile(`(?i)<meta\s+[^>]*content\s*=\s*["']([^"']*)["'][^>]*name\s*=\s*["']description["'][^>]*/?>`)
		if matches := metaDescRe2.FindStringSubmatch(html); len(matches) > 1 {
			description = strings.TrimSpace(matches[1])
		}
	}

	return title, description
}

func init() {
	// Allow localhost for testing when ALLOW_LOCALHOST env is set
	if os.Getenv("ALLOW_LOCALHOST") == "true" {
		AllowLocalhost = true
	}
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

