			}
			if err := validateHost(req.URL.Host); err != nil {
				return fmt.Errorf("redirect to private address not allowed")
			}
			return nil
		},
	}

	httpReq, err := http.NewRequest(http.MethodGet, parsedURL.String(), nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Failed to create request"})
	}
