		"fc00::/7",
		"fe80::/10",
		"::ffff:127.0.0.0/104",
		"::ffff:10.0.0.0/104",
		"::ffff:172.16.0.0/108",
		"::ffff:192.168.0.0/112",
		"::ffff:169.254.0.0/112",
	}

	for _, cidr := range privateRanges {
		_, network, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if network.Contains(ip) {
			return true
		}
	}
	return false
}

// validateHost resolves the hostname and checks that it doesn't point to a private IP
func validateHost(hostname string) error {
	// If it's already an IP, check directly
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
		return nil
	}

	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %w", err)
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	return nil
}

// safeTransport creates a transport that blocks connections to private IPs
func safeTransport() *http.Transport {
	return &http.Transport{
